def dedupe_sorted(a):
    # your code here
    return 0

solution:
def dedupe_sorted(a):
    if not a:
        return 0
    w = 1
    for r in range(1, len(a)):
        if a[r] != a[w - 1]:
            a[w] = a[r]
            w += 1
    return w

