def sorted_intersection(A, B):
    # your code here
    return []

solution:
def sorted_intersection(A, B):
    i = j = 0
    out = []
    while i < len(A) and j < len(B):
        if A[i] == B[j]:
            out.append(A[i])
            i += 1
            j += 1
        elif A[i] < B[j]:
            i += 1
        else:
            j += 1
    return out

