    return ''

solution:
def compress(s):
    i = 0
    res = ''
    while i < len(s):
        j = i
        while j < len(s) and s[j] == s[i]:
            j += 1
        res += s[i]
        if j - i > 1:
            res += str(j - i)
        i = j
    return res

